import java.util.PriorityQueue

fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val directions = listOf(0 to 1, 1 to 0)

    // Priority queue: (total_cost, i, j, remaining_teleports)
    val heap = PriorityQueue<Pair<Long, Triple<Int, Int, Long>>>(compareBy { it.first })
    heap.add(0L to Triple(0, 0, k))

    // Visited: (i, j, remaining_teleports) -> min_cost
    val visited = mutableMapOf<Triple<Int, Int, Long>, Long>()
    visited[Triple(0, 0, k)] = 0L

    while (heap.isNotEmpty()) {
        val (cost, state) = heap.poll()
        val (i, j, tele) = state
        if (i == m - 1 && j == n - 1) {
            return cost
        }
        if (visited.getOrDefault(state, Long.MAX_VALUE) < cost) {
            continue
        }

        // Normal moves
        for ((di, dj) in directions) {
            val ni = i + di
            val nj = j + dj
            if (ni in 0 until m && nj in 0 until n) {
                val newCost = cost + grid[ni][nj]
                val newState = Triple(ni, nj, tele)
                if (newCost < visited.getOrDefault(newState, Long.MAX_VALUE)) {
                    visited[newState] = newCost
                    heap.add(newCost to newState)
                }
            }
        }

        // Teleport moves
        if (tele > 0) {
            for (ni in 0 until m) {
                for (nj in 0 until n) {
                    if ((ni != i || nj != j) && grid[ni][nj] <= grid[i][j]) {
                        val newTele = tele - 1
                        val newState = Triple(ni, nj, newTele)
                        if (cost < visited.getOrDefault(newState, Long.MAX_VALUE)) {
                            visited[newState] = cost
                            heap.add(cost to newState)
                        }
                    }
                }
            }
        }
    }

    return -1L
}
